suspend fun loadIfMissing(key: String): Value {
    cache[key]?.let { return it }
    val remote = api.load(key) // suspend; coroutine khác có thể đã ghi cache
    cache[key] = remote
    return remote
}

class MessageStore {
    private val mutex = Mutex()
    private val byClientId = mutableMapOf<String, Message>()

    suspend fun apply(event: MessageEvent): Message? = mutex.withLock {
        val current = byClientId[event.clientId] ?: return@withLock null

        val mergedServerId = when {
            current.serverId == null -> event.serverId
            event.serverId == null -> current.serverId
            current.serverId == event.serverId -> current.serverId
            else -> throw IdentityConflict(event.clientId)
        }

        val next = current.copy(
            serverId = mergedServerId,
            status = maxOf(current.status, event.status),
            updatedAt = maxOf(current.updatedAt, event.timestamp)
        )
        byClientId[event.clientId] = next
        next
    }
}

private val _state = MutableStateFlow(ChatState())
val state: StateFlow<ChatState> = _state.asStateFlow()

fun apply(event: MessageEvent) {
    _state.update { old ->
        old.copy(messages = old.messages.merge(event))
    }
}

val ref = AtomicReference(SessionState())

fun markConnected() {
    while (true) {
        val old = ref.get()
        val next = old.copy(isConnected = true, generation = old.generation + 1)
        if (ref.compareAndSet(old, next)) return
    }
}

class ChatActor(scope: CoroutineScope) {
    private val commands = Channel<MessageEvent>(capacity = Channel.BUFFERED)
    private val state = mutableMapOf<String, Message>()

    init {
        scope.launch {
            for (event in commands) {
                state[event.clientId] = merge(state[event.clientId], event)
            }
        }
    }

    suspend fun submit(event: MessageEvent) = commands.send(event)
}

@Transaction
suspend fun applyAck(event: AckEntity) {
    val current = messageDao.findByClientId(event.clientId) ?: return
    val next = current.copy(
        serverId = current.serverId ?: event.serverId,
        status = maxOf(current.status, event.status)
    )
    messageDao.update(next)
}
